import { useEffect, useState } from "react";

import JobForm from "./components/JobForm";
import Dashboard from "./components/Dashboard";
import JobFilters from "./components/JobFilters";
import JobBoard from "./components/JobBoard";

import type { Job, JobForm as JobFormType } from "./types/jobs";


function App() {

  const initialJob: JobFormType = {
      company: "",
          position: "",
              salary: "",
                  modality: "Remoto",
                      status: "Enviado",
                        };


                          const [job, setJob] =
                              useState<JobFormType>(initialJob);



                                const [jobs, setJobs] =
                                    useState<Job[]>(() => {

                                          const savedJobs =
                                                  localStorage.getItem("jobs");


                                                        if (!savedJobs) return [];


                                                              const parsedJobs: Job[] =
                                                                      JSON.parse(savedJobs);


                                                                            return parsedJobs.map((job) => ({

                                                                                    ...job,

                                                                                            id:
                                                                                                      job.id ??
                                                                                                                crypto.randomUUID(),

                                                                                                                        appliedAt:
                                                                                                                                  job.appliedAt ??
                                                                                                                                            new Date().toISOString(),

                                                                                                                                                    updatedAt:
                                                                                                                                                              job.updatedAt ??
                                                                                                                                                                        new Date().toISOString(),

                                                                                                                                                                              }));

                                                                                                                                                                                  });



                                                                                                                                                                                    const [editingId, setEditingId] =
                                                                                                                                                                                        useState<string | null>(null);



                                                                                                                                                                                          const [search, setSearch] =
                                                                                                                                                                                              useState("");



                                                                                                                                                                                                const [statusFilter, setStatusFilter] =
                                                                                                                                                                                                    useState("Todos");





                                                                                                                                                                                                      const filteredJobs =
                                                                                                                                                                                                          jobs.filter((job) => {

                                                                                                                                                                                                                const searchLower =
                                                                                                                                                                                                                        search.toLowerCase();


                                                                                                                                                                                                                              const matchesSearch =
                                                                                                                                                                                                                                      job.company
                                                                                                                                                                                                                                                .toLowerCase()
                                                                                                                                                                                                                                                          .includes(searchLower)

                                                                                                                                                                                                                                                                  ||

                                                                                                                                                                                                                                                                          job.position
                                                                                                                                                                                                                                                                                    .toLowerCase()
                                                                                                                                                                                                                                                                                              .includes(searchLower);



                                                                                                                                                                                                                                                                                                    const matchesStatus =
                                                                                                                                                                                                                                                                                                            statusFilter === "Todos"

                                                                                                                                                                                                                                                                                                                    ||

                                                                                                                                                                                                                                                                                                                            job.status === statusFilter;



                                                                                                                                                                                                                                                                                                                                  return matchesSearch && matchesStatus;

                                                                                                                                                                                                                                                                                                                                      });






                                                                                                                                                                                                                                                                                                                                        useEffect(() => {

                                                                                                                                                                                                                                                                                                                                            localStorage.setItem(
                                                                                                                                                                                                                                                                                                                                                  "jobs",
                                                                                                                                                                                                                                                                                                                                                        JSON.stringify(jobs)
                                                                                                                                                                                                                                                                                                                                                            );

                                                                                                                                                                                                                                                                                                                                                              }, [jobs]);







                                                                                                                                                                                                                                                                                                                                                                function handleSubmit() {


                                                                                                                                                                                                                                                                                                                                                                    if (!job.company || !job.position) {

                                                                                                                                                                                                                                                                                                                                                                          alert(
                                                                                                                                                                                                                                                                                                                                                                                  "Preencha empresa e cargo."
                                                                                                                                                                                                                                                                                                                                                                                        );

                                                                                                                                                                                                                                                                                                                                                                                              return;

                                                                                                                                                                                                                                                                                                                                                                                                  }



                                                                                                                                                                                                                                                                                                                                                                                                      const now =
                                                                                                                                                                                                                                                                                                                                                                                                            new Date().toISOString();




                                                                                                                                                                                                                                                                                                                                                                                                                if (editingId) {


                                                                                                                                                                                                                                                                                                                                                                                                                      setJobs((prev) =>

                                                                                                                                                                                                                                                                                                                                                                                                                              prev.map((item) =>

                                                                                                                                                                                                                                                                                                                                                                                                                                        item.id === editingId

                                                                                                                                                                                                                                                                                                                                                                                                                                                    ? {

                                                                                                                                                                                                                                                                                                                                                                                                                                                                    ...item,

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    ...job,

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    updatedAt: now,

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  }

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              : item

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      )

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            );


                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  setEditingId(null);



                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      } else {


                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            const newJob: Job = {

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    id: crypto.randomUUID(),

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            ...job,

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    appliedAt: now,

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            updatedAt: now,

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  };



                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        setJobs((prev) => [

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                ...prev,

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        newJob

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              ]);

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  }



                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      setJob(initialJob);

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        }









                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          function editJob(id: string) {

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            console.log("APP:", id);


                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              const jobToEdit =
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  jobs.find(
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        (job) => job.id === id
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            );


                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              console.log(
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  "VAGA:",
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      jobToEdit
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        );


                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          if (!jobToEdit) return;


                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            setJob({

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                company: jobToEdit.company,

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    position: jobToEdit.position,

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        salary: jobToEdit.salary,

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            modality: jobToEdit.modality,

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                status: jobToEdit.status,

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  });


                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    setEditingId(id);

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    }







                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      function moveJob(
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          id: string,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              newStatus: string
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                ) {


                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    setJobs((prev) =>

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          prev.map((job) =>

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  job.id === id

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            ? {

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          ...job,

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        status: newStatus,

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      updatedAt:
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      new Date().toISOString(),

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  }

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            : job

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  )

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      );

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        }







                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          function deleteJob(id: string) {


                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              const confirmDelete =
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    window.confirm(
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            "Tem certeza que deseja excluir esta vaga?"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  );



                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      if (!confirmDelete) return;



                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          setJobs((prev) =>

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                prev.filter(
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        (job) => job.id !== id
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              )

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  );

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    }







                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      return (

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          <main>


                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          <header className="header">

  <h1 className="title">
    JobFlow
  </h1>

  <p className="subtitle">
    Organize suas candidaturas de forma simples.
  </p>

</header>
<section className="section">

  <h2 className="section-title">
    Resumo
  </h2>

  <Dashboard
    jobs={jobs}
  />

</section>

<section>
<h2>                                                                                                                   {editingId ? "Editar vaga" : "Nova vaga"
                                                                                                                     }

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        </h2>



                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                <JobForm

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          job={job}

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    setJob={setJob}

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              handleSubmit={handleSubmit}

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        editingId={editingId}

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                />


                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      </section>






                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            <JobFilters

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    search={search}

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            setSearch={setSearch}

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    statusFilter={statusFilter}

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            setStatusFilter={setStatusFilter}

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  />







                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        <section>


                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                <h2>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          Suas vagas
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  </h2>



                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    filteredJobs.length === 0 ? (

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                <p>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              Nenhuma vaga encontrada.
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          </p>


                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    ) : (

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                <JobBoard

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              jobs={filteredJobs}

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            editJob={editJob}

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          deleteJob={deleteJob}

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        moveJob={moveJob}

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    />

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              )

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      }


                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            </section>



                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                </main>

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  );

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  }


                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  export default App;